using System;
using System.Reflection;
using System.Linq;

var asm = Assembly.LoadFrom(Environment.GetCommandLineArgs().Last());
var assertType = asm.GetType("Microsoft.VisualStudio.TestTools.UnitTesting.Assert");
var methods = assertType.GetMethods(BindingFlags.Public | BindingFlags.Static)
    .Where(m => m.Name == "AreEqual" || m.Name == "AreNotEqual" || m.Name == "AreSame" || m.Name == "AreNotSame")
    .Where(m => m.IsGenericMethod);
foreach (var m in methods.Take(10)) {
    var genArgs = m.GetGenericArguments();
    foreach (var g in genArgs) {
        var constraints = g.GetGenericParameterConstraints();
        var attrs = g.GenericParameterAttributes;
        Console.WriteLine($"{m.Name} - {g.Name}: attrs={attrs}, constraints=[{string.Join(",", constraints.Select(c => c.Name))}]");
    }
    var parms = m.GetParameters();
    foreach (var p in parms) {
        var isOptional = p.IsOptional;
        var defaultVal = p.HasDefaultValue ? p.DefaultValue?.ToString() ?? "null" : "N/A";
        var callerAttrs = p.GetCustomAttributes().Select(a => a.GetType().Name);
        Console.WriteLine($"  {p.Name}: optional={isOptional}, default={defaultVal}, attrs=[{string.Join(",", callerAttrs)}]");
    }
    Console.WriteLine();
}
EOF
